package main

import (
	"container/heap"
)

type Item struct {
	cost int64
	time int64
	i    int64
	j    int64
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}
func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}
func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}
func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(m int64, n int64, waitCost [][]int64) int64 {
	directions := [][]int64{{0, 1}, {1, 0}}
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	initialCost := (0 + 1) * (0 + 1)
	heap.Push(&pq, &Item{cost: initialCost, time: 1, i: 0, j: 0})

	visited := make(map[[3]int64]int64)
	key := [3]int64{1 % 2, 0, 0}
	visited[key] = initialCost

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		currentCost := item.cost
		time := item.time
		i := item.i
		j := item.j

		if i == m-1 && j == n-1 {
			return currentCost
		}

		if time%2 == 1 {
			for _, dir := range directions {
				ni := i + dir[0]
				nj := j + dir[1]
				if ni >= 0 && ni < m && nj >= 0 && nj < n {
					newTime := time + 1
					newCost := currentCost + (ni+1)*(nj+1)
					key := [3]int64{newTime % 2, ni, nj}
					if val, exists := visited[key]; !exists || newCost < val {
						visited[key] = newCost
						heap.Push(&pq, &Item{cost: newCost, time: newTime, i: ni, j: nj})
					}
				}
			}
		} else {
			newTime := time + 1
			newCost := currentCost + waitCost[i][j]
			key := [3]int64{newTime % 2, i, j}
			if val, exists := visited[key]; !exists || newCost < val {
				visited[key] = newCost
				heap.Push(&pq, &Item{cost: newCost, time: newTime, i: i, j: j})
			}
		}
	}
	return -1
}
