	visited := make(map[[3]int64]int64)
	key := [3]int64{1 % 2, 0, 0}
	visited[key] = initialCost

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*Item)
		currentCost := current.cost
		currentTime := current.time
		i := current.i
		j := current.j

		if i == m-1 && j == n-1 {
			return currentCost
		}

		if currentTime%2 == 1 {
			for _, dir := range directions {
				ni, nj := i+dir[0], j+dir[1]
				if ni >= 0 && ni < m && nj >= 0 && nj < n {
					newTime := currentTime + 1
					newCost := currentCost + (ni+1)*(nj+1)
					key := [3]int64{newTime % 2, ni, nj}
					if val, exists := visited[key]; !exists || newCost < val {
						visited[key] = newCost
						heap.Push(&pq, &Item{cost: newCost, time: newTime, i: ni, j: nj})
					}
				}
			}
		} else {
			newTime := currentTime + 1
			newCost := currentCost + waitCost[i][j]
			key := [3]int64{newTime % 2, i, j}
			if val, exists := visited[key]; !exists || newCost < val {
				visited[key] = newCost
				heap.Push(&pq, &Item{cost: newCost, time: newTime, i: i, j: j})
			}
		}
	}
	return -1
